import{_ as a,o,c as r,a2 as t}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-038 — Per-body 2D projection: Mars equirectangular, Moon orthographic dual-disc","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-038.md","filePath":"adr/ADR-038.md"}'),i={name:"adr/ADR-038.md"};function s(n,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[t(`<h1 id="adr-038-—-per-body-2d-projection-mars-equirectangular-moon-orthographic-dual-disc" tabindex="-1">ADR-038 — Per-body 2D projection: Mars equirectangular, Moon orthographic dual-disc <a class="header-anchor" href="#adr-038-—-per-body-2d-projection-mars-equirectangular-moon-orthographic-dual-disc" aria-label="Permalink to &quot;ADR-038 — Per-body 2D projection: Mars equirectangular, Moon orthographic dual-disc&quot;">​</a></h1><blockquote><p>Status · Accepted (closes RFC-012 OQ-2) Date · 2026-05-09 (back-filled from v0.4.0 implementation) Closes · RFC-012 OQ-2 (&quot;2D projection for Mars&quot;) TA anchor · §components/surface-routes Related ADRs · ADR-037 (shared surface-site type), ADR-039 (cross-link contract)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p><code>/moon</code> shipped in v0.1 with a 2D view of two side-by-side orthographic discs (near side + far side) — the natural visual for a tidally-locked body where the always-Earth-facing hemisphere is a meaningful entity.</p><p><code>/mars</code> arrived in v0.4. RFC-012 OQ-2 asked: does the same orthographic-pair pattern transfer? Mars has no permanent far side (rotation period ≈ 24h 37m, not synchronous with Earth) so the &quot;near vs far&quot; semantic doesn&#39;t apply. Three projection candidates were considered:</p><table tabindex="0"><thead><tr><th>Projection</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Equirectangular</strong> (cylindrical lat/lon grid)</td><td>Familiar from NASA Mars maps; lat/lon → pixel is trivial; rover traverses lay flat</td><td>Polar regions exaggerated</td></tr><tr><td><strong>Orthographic dual-disc</strong> (Mars equivalent of /moon&#39;s near/far)</td><td>Visual parity with /moon</td><td>&quot;Near&quot; / &quot;far&quot; arbitrary on Mars; users would need to learn what each disc means</td></tr><tr><td><strong>Mollweide / equal-area</strong></td><td>Polar regions truthful</td><td>Less recognisable; rover traverse rendering more complex</td></tr></tbody></table><p>Independent decision per body — RFC-012 explicitly asked us to lock the projection per-body, not globally.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="mars-—-equirectangular" tabindex="-1">Mars — equirectangular <a class="header-anchor" href="#mars-—-equirectangular" aria-label="Permalink to &quot;Mars — equirectangular&quot;">​</a></h3><p><code>/mars</code> 2D mode uses a single equirectangular projection. Latitude on the y-axis (-90° south at top → +90° north at bottom — flipped from raw lat so positive-y maps to north visually), longitude on the x-axis (-180° west to +180° east). Pixel coordinate computation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>px = (lon + 180) / 360 × canvas.width</span></span>
<span class="line"><span>py = (90 - lat) / 180 × canvas.height</span></span></code></pre></div><p>Rover traverses (per RFC-012 OQ-6) render as polylines through the same projection.</p><h3 id="moon-—-keep-orthographic-dual-disc" tabindex="-1">Moon — keep orthographic dual-disc <a class="header-anchor" href="#moon-—-keep-orthographic-dual-disc" aria-label="Permalink to &quot;Moon — keep orthographic dual-disc&quot;">​</a></h3><p><code>/moon</code> 2D mode keeps its existing orthographic-pair view (near side + far side discs side-by-side). Tidal-lock is a real semantic distinction worth surfacing visually; replacing it with equirectangular for parity with Mars would lose information.</p><h3 id="polar-projection-toggle-—-deferred" tabindex="-1">Polar-projection toggle — deferred <a class="header-anchor" href="#polar-projection-toggle-—-deferred" aria-label="Permalink to &quot;Polar-projection toggle — deferred&quot;">​</a></h3><p>A third &quot;polar projection&quot; toggle (north-pole / south-pole stereographic) was considered for Mars to handle the Polar Lander (Mars Polar Lander, Phoenix) sites. Deferred — the equirectangular projection still places these sites correctly, just with exaggerated polar pixel area; the polar projection is a polish-tier feature for a future minor release.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>The equirectangular pattern is what every NASA Mars map ships in — users recognise it instantly; lat/lon labels read directly off the axes.</li><li>Forcing Mars onto the orthographic dual-disc pattern would require an arbitrary &quot;near&quot; / &quot;far&quot; choice (Mars has neither) — the visual would lie.</li><li>Keeping <code>/moon</code> on its orthographic-pair view preserves the tidal-lock semantic that distinguishes the Moon from every other body.</li><li>Per-body projection means the projection helper functions become per-body too — modest additional code, minimal abstraction cost.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Force a single global projection for both bodies</strong> (option: equirectangular for both) — rejected because losing /moon&#39;s near/far discs would erase the tidal-lock visual cue.</li><li><strong>Stereographic-pair for Mars</strong> — closer to /moon visually but no payoff (no semantic basis for splitting Mars into &quot;near&quot; and &quot;far&quot;).</li><li><strong>Mollweide equal-area for Mars</strong> — accurate but unfamiliar; deferred until users ask for it.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>Each body&#39;s 2D view matches the conventions readers see in agency maps for that body.</li><li>Tidal-lock semantic preserved on /moon.</li><li>Rover traverse rendering on /mars is a one-liner per polyline (project lat/lon → pixel).</li></ul><p><strong>Negative:</strong></p><ul><li>Per-body projection helpers (no shared component for the 2D path — see ADR-037).</li><li>Polar regions on Mars are visually exaggerated; addressed by future polar-projection toggle if/when needed.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><code>src/routes/mars/+page.svelte</code> — equirectangular <code>draw2d()</code> + lat/lon → pixel helper inline.</li><li><code>src/routes/moon/+page.svelte</code> — orthographic-pair <code>draw2d()</code> (unchanged from v0.1).</li><li>Atmosphere-shell layer (lens-gated, ADR-055) overlays consistently in both 3D modes; the 2D modes don&#39;t carry the atmosphere overlay.</li></ul>`,27)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
